75:   public void testCreateRule(@TestParameter boolean explicitlySetGeneratorAttrs) throws Exception {
76:     Path myPkgPath = scratch.resolve("/workspace/mypkg/BUILD");
77:     Package.Builder pkgBuilder = newBuilder(PackageIdentifier.createInMainRepo("mypkg"), myPkgPath);
78: 
79:     Map<String, Object> attributeValues = new HashMap<>();
80:     attributeValues.put("name", "foo");
81:     attributeValues.put("executable", true);
82:     attributeValues.put("outs", ImmutableList.of("foo.out"));
83:     attributeValues.put("cmd", "echo");
84: 
85:     // TODO(b/274802222): Should this be prohibited?
86:     if (explicitlySetGeneratorAttrs) {
87:       attributeValues.put("generator_name", "fake_generator_name");
88:       attributeValues.put("generator_function", "fake_generator_function");
89:     }
90: 
91:     RuleClass ruleClass = provider.getRuleClassMap().get("genrule");
92:     Rule rule =
93:         RuleFactory.createAndAddRule(
94:             pkgBuilder,
95:             ruleClass,
96:             new BuildLangTypedAttributeValuesMap(attributeValues),
97:             true,
98:             DUMMY_STACK);
99: 
100:     assertThat(rule.getAssociatedRule()).isSameInstanceAs(rule);
101: 
102:     // pkg.getRules() = [rule]
103:     Package pkg = pkgBuilder.build();
104:     assertThat(Sets.newHashSet(pkg.getTargets(Rule.class))).hasSize(1);
105:     assertThat(pkg.getTargets(Rule.class).iterator().next()).isEqualTo(rule);
106: 
107:     assertThat(pkg.getTarget("foo")).isSameInstanceAs(rule);
108: 
109:     assertThat(rule.getLabel()).isEqualTo(Label.parseCanonical("//mypkg:foo"));
110:     assertThat(rule.getName()).isEqualTo("foo");
111: 
112:     assertThat(rule.getRuleClass()).isEqualTo("genrule");
113:     assertThat(rule.getTargetKind()).isEqualTo("genrule rule");
114:     // The rule reports the location of the outermost call (aka generator), in the BUILD file.
115:     // This behavior was added to fix b/23974287, but it loses information and is redundant
116:     // w.r.t. generator_location. A better fix to that issue would be to keep rule.location as
117:     // the innermost call, and to report the entire call stack at the first error for the rule.
118:     assertThat(rule.getLocation().file()).isEqualTo("BUILD");
119:     assertThat(rule.getLocation().line()).isEqualTo(42);
120:     assertThat(rule.getLocation().column()).isEqualTo(1);
121:     assertThat(rule.containsErrors()).isFalse();
122: 
123:     // Attr with explicitly-supplied value:
124:     AttributeMap attributes = RawAttributeMapper.of(rule);
125:     assertThat(attributes.get("executable", Type.BOOLEAN)).isTrue();
126:     assertThrows(Exception.class, () -> attributes.get("tools", Type.STRING));
127:     assertThrows(Exception.class, () -> attributes.get("nosuchattr", Type.STRING));
128: 
129:     // Attrs with default values:
130:     // cc_library linkstatic default=0 according to build encyc.
131:     assertThat(attributes.get("output_to_bindir", Type.BOOLEAN)).isFalse();
132:     assertThat(attributes.get("testonly", Type.BOOLEAN)).isFalse();
133:     assertThat(attributes.get("srcs", BuildType.LABEL_LIST)).isEmpty();
134:   }
