package com.google.devtools.build.lib.packages;

// Tests for Starlark rule evaluation

@RunWith(JUnit4.class)
public final class StarlarkRuleEvalTest extends PackageLoadingTestCase {

  // High-level tests using scratch.file() + loadPackage()

  @Test
  public void testBasicRuleInstantiation() throws Exception {
    scratch.file("mypkg/BUILD", "cc_library(name = 'mylib')");
    Package pkg = loadPackage("mypkg");
    assertNoEvents();
    assertThat(pkg.containsErrors()).isFalse();
    Rule rule = pkg.getRule("mylib");
    assertThat(rule).isNotNull();
    assertThat(rule.getName()).isEqualTo("mylib");
    assertThat(rule.getRuleClass()).isEqualTo("cc_library");
  }

  @Test
  public void testMissingRequiredAttributeProducesError() throws Exception {
    reporter.removeHandler(failFastHandler);
    // genrule requires: name, outs, cmd
    scratch.file("mypkg/BUILD", "genrule(name = 'myrule', outs = ['out.txt'])");
    Package pkg = loadPackage("mypkg");
    assertContainsEvent("missing value for mandatory attribute 'cmd'");
    assertThat(pkg.containsErrors()).isTrue();
  }

  @Test
  public void testAttributeTypeValidation_stringWhereListExpected() throws Exception {
    reporter.removeHandler(failFastHandler);
    // srcs expects a list, not a string
    scratch.file("mypkg/BUILD", "cc_library(name = 'mylib', srcs = 'foo.cc')");
    Package pkg = loadPackage("mypkg");
    assertContainsEvent("expected value of type 'list(label)'");
    assertThat(pkg.containsErrors()).isTrue();
  }

  @Test
  public void testDefaultAttributeValuesAreApplied() throws Exception {
    scratch.file("mypkg/BUILD", "cc_library(name = 'mylib')");
    Package pkg = loadPackage("mypkg");
    assertNoEvents();
    Rule rule = pkg.getRule("mylib");
    AttributeMap attrs = RawAttributeMapper.of(rule);
    // testonly defaults to false
    assertThat(attrs.get("testonly", Type.BOOLEAN)).isFalse();
    // srcs defaults to empty list
    assertThat(attrs.get("srcs", BuildType.LABEL_LIST)).isEmpty();
  }

  @Test
  public void testVisibilityAttributeHandling() throws Exception {
